mapper.select:
SELECT b.book_id, b.book_title, b.author_name, b.publisher, b.publish_date, b.book_price, -- 재고가 0이면 품절로 표시, 아니면 원래 상태 유지 CASE WHEN b.book_stock = 0 THEN '품절' ELSE b.stock_status END AS stock_status, b.book_summary, b.cover_image, b.category_id, c.category_name_ko, b.isbn, b.book_stock, b.created_at, b.updated_at, IFNULL(SUM(oi.book_quantity), 0) AS sales_count, -- 판매 수량 IFNULL(AVG(r.review_score), 0) AS average_rating, -- 평점 평균 COUNT(r.review_id) AS review_count -- 리뷰 수 FROM book b LEFT JOIN orderitem oi ON b.book_id = oi.book_id LEFT JOIN review r ON b.book_id = r.book_id LEFT JOIN category c ON b.category_id = c.category_id
AND (b.book_title LIKE CONCAT('%', #{search}, '%') OR b.author_name LIKE CONCAT('%', #{search}, '%'))
AND b.category_id = #{category_id}
AND b.stock_status = #{stock_status}
GROUP BY b.book_id
ORDER BY sales_count DESC ORDER BY b.created_at DESC ORDER BY review_count DESC ORDER BY average_rating DESC ORDER BY b.book_id DESC
LIMIT #{pageStart}, #{perPageNum}

mapper.update:
UPDATE book
SET stock_status = #{stock_status}
WHERE book_id = #{book_id}

UPDATE book
SET category_id = #{category_id}
WHERE book_id = #{book_id}

